  ('social-worker-moex-04830', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「團體工作」的信念在實踐以人道為主的社會服務過程，下列那一個敘述最能夠表達這樣的精神？', '["團體工作係由具備特定社會工作知識與方法的人進行有意識的團體運用", "團體工作的目的在提升成員的社會功能", "團體是一個整體，而非個體的加總", "團體工作者應具備民主素養，以承載不同個體的自主意願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04831', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者是串連服務對象與社區資源，將個案的需求與提供服務的機構進行媒合，非只是提供 資源名單給個案，而是讓轉介發揮最大效益。此為社會工作者的何項角色？', '["諮商者", "倡導者", "團體催化者", "經紀人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04832', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '培養文化能力是社會工作者重要的核心能力，下列何者不是「培養多元文化能力」的正確描述？', '["社會工作者的自我覺察", "社會工作者對「差異」保持開放的態度", "社會工作者相信主流文化具有普同性", "社會工作者持續擴展文化的知識與資源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04833', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關「理論」與社會工作「實務」之間的關連，何者敘述錯誤？', '["理論可以指引社會工作者，讓社會工作者知道決定如何進行處遇", "由於理論過於抽象，社會工作者可依主觀判斷設計處遇計畫", "理論與實務工作息息相關，須隨著社會結構變遷而做出修正", "累積實務經驗有助於理論處遇模式之建構"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04834', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於社會工作心理暨社會學派發展之敘述，何者正確？①早期以心理動力為主要知識基礎', '["強調運用關係過程和機構功能連接，以讓案主透過機構功能來實踐其獨特性", "延續診斷派的 傳統，重視平衡個人心理、人際與環境的交互影響力", "強調環境壓力若是大到案主無法處理 時，也不需要介入協助造成案主的環境壓力因素", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04835', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者運用認知行為理論的角色及任務，與其他理論取向不同，下列敘述何者錯誤？', '["社會工作者協助案主回顧早年經驗，以增加案主對個人性格特質的覺知", "社會工作者提供案主示範與增強，協助案主養成正向的因應行為", "社會工作者指派與督促案主完成家庭作業", "社會工作者像教練，指導訓練案主覺察自己的不合理信念"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04836', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者在運用焦點解決短期治療（Solution-Focused Brief Therapy, SFBT）於處遇過程時，應 注意焦點解決的特性不包含下列何者？', '["焦點解決強調案主的優勢", "長時間傾聽案主訴說人生苦難的詳細內容是不必要的", "焦點解決的目標導向聚焦於小小的改變可促成系統性改變", "實務工作者的專業權威有助於短期解決問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04837', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的任務中心取向（Task-Centered Approach）起源於試圖以有計劃的短期處遇取代傳統的 長期處遇方法，下列關於任務中心取向之敘述何者錯誤？', '["任務中心取向假設人沒有改變動力，需要實務工作者指派任務", "任務中心取向的「任務」反映了案主的日常生活經驗和需求，指出案主在處遇中需要做什麼", "任務執行（task implementation）之前要分析案主的潛在障礙，辨識是社會環境、人際交流障礙 或案主個人心理狀態所致", "任務中心取向的「目標」代表案主在完成「任務」後所呈現的狀況"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04838', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '一位失業單親父親無親友支持系統，其居住的社區托育服務資源稀缺且昂貴。每次應徵工作時，就 將5歲的孩子獨留家中，而觸法。根據生態系統模式的處遇分析與計畫擬定，下列敘述何者正確？', '["行動系統是為達成處遇目標時所需合作的正式與非正式資源", "標的系統是依法開罰該名單親失業父親", "機構系統是該名父親未來就業的單位", "案主系統是社區中負責托育的公共部門"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04839', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「倡導者」為社會工作的專業角色之一，下列相關敘述何者正確？①為免服務中斷，社會工作者', '["社會工作者強化服務對象的優勢，以增進資源及權利的公平分配", "倡導可 以為個案倡導，亦可以為政策倡導", "倡導在為服務對象個體或群體爭取應得的福利服務", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
